# ══════════════════════════════════════════════════════════════════════════════
# ANIMATION UTILITIES
# ══════════════════════════════════════════════════════════════════════════════

class Easing:
    """
    Curated easing curve constants used consistently throughout the UI.
    Using named aliases prevents magic QEasingCurve.Type values scattered
    across the codebase.
    """
    # Screen transitions
    TRANSITION_IN  = QEasingCurve.Type.OutCubic
    TRANSITION_OUT = QEasingCurve.Type.InCubic

    # Button / interactive element feedback
    BUTTON_PRESS   = QEasingCurve.Type.OutBack
    BUTTON_RELEASE = QEasingCurve.Type.InOutCubic

    # Slide panels (sidebars, drawers)
    SLIDE_OPEN  = QEasingCurve.Type.OutQuart
    SLIDE_CLOSE = QEasingCurve.Type.InQuart

    # Toast / notification fly-in
    TOAST_IN  = QEasingCurve.Type.OutBack
    TOAST_OUT = QEasingCurve.Type.InQuart

    # Value counters (gold change flash)
    VALUE_POP  = QEasingCurve.Type.OutElastic
    VALUE_FADE = QEasingCurve.Type.InQuad

    # Generic smooth
    SMOOTH = QEasingCurve.Type.InOutCubic
    LINEAR = QEasingCurve.Type.Linear


class FadeEffect:
    """
    Manages a QGraphicsOpacityEffect + QPropertyAnimation on a target widget.
    Provides  fade_in(ms) / fade_out(ms, on_done)  methods.
    The effect is owned by the target widget (reparented to it).
    """

    def __init__(self, widget: QWidget) -> None:
        self._w = widget
        self._anim: Optional[QPropertyAnimation] = None

    def fade_in(self, duration_ms: int = 220,
                easing: QEasingCurve.Type = Easing.TRANSITION_IN) -> None:
        self._run(0.0, 1.0, duration_ms, easing)

    def fade_out(self, duration_ms: int = 180,
                 easing: QEasingCurve.Type = Easing.TRANSITION_OUT,
                 on_done: Optional[Callable] = None) -> None:
        self._run(1.0, 0.0, duration_ms, easing, on_done)

    def _run(self, start: float, end: float, ms: int,
             easing: QEasingCurve.Type,
             on_done: Optional[Callable] = None) -> None:
        # Stop any running animation
        try:
            if self._anim and self._anim.state() == QAbstractAnimation.State.Running:
                self._anim.stop()
        except RuntimeError:
            pass
        self._anim = None

        # Create a fresh effect for this animation only; remove it when done
        # so the widget never has a permanent QGraphicsEffect (which would
        # cause nested-painter QPainter errors if a child also sets one).
        eff = QGraphicsOpacityEffect(self._w)
        eff.setOpacity(start)
        self._w.setGraphicsEffect(eff)

        a = QPropertyAnimation(eff, b"opacity", self._w)
        a.setDuration(ms)
        a.setStartValue(start)
        a.setEndValue(end)
        a.setEasingCurve(easing)

        def _cleanup() -> None:
            self._w.setGraphicsEffect(None)  # type: ignore[arg-type]
            self._anim = None
            if on_done:
                on_done()

        a.finished.connect(_cleanup)
        self._anim = a
        a.start(QAbstractAnimation.DeletionPolicy.DeleteWhenStopped)


class SlideEffect:
    """
    Animates a widget's geometry to slide in from a given edge.
    Only suitable for top-level panels / drawers.
    """

    class Edge(Enum):
        TOP    = "top"
        BOTTOM = "bottom"
        LEFT   = "left"
        RIGHT  = "right"

    def __init__(self, widget: QWidget, edge: "SlideEffect.Edge") -> None:
        self._w    = widget
        self._edge = edge
        self._anim: Optional[QPropertyAnimation] = None

    def slide_in(self, duration_ms: int = 280) -> None:
        self._run(show=True, ms=duration_ms)

    def slide_out(self, duration_ms: int = 220,
                  on_done: Optional[Callable] = None) -> None:
        self._run(show=False, ms=duration_ms, on_done=on_done)

    def _run(self, show: bool, ms: int,
             on_done: Optional[Callable] = None) -> None:
        try:
            if self._anim and self._anim.state() == QAbstractAnimation.State.Running:
                self._anim.stop()
        except RuntimeError:
            pass
        self._anim = None

        w = self._w
        parent = w.parent()
        if parent is None:
            return

        pw, ph = parent.width(), parent.height()  # type: ignore[union-attr]
        ww, wh = w.width() or UIScale.px(300), w.height() or ph

        hidden_geo = w.geometry()
        shown_geo  = w.geometry()

        edge = self._edge
        if edge == SlideEffect.Edge.RIGHT:
            hidden_geo.moveLeft(pw)
            shown_geo.moveLeft(pw - ww)
        elif edge == SlideEffect.Edge.LEFT:
            hidden_geo.moveLeft(-ww)
            shown_geo.moveLeft(0)
        elif edge == SlideEffect.Edge.TOP:
            hidden_geo.moveTop(-wh)
            shown_geo.moveTop(0)
        elif edge == SlideEffect.Edge.BOTTOM:
            hidden_geo.moveTop(ph)
            shown_geo.moveTop(ph - wh)

        start_geo = hidden_geo if show else shown_geo
        end_geo   = shown_geo  if show else hidden_geo

        w.setGeometry(start_geo)
        w.show() if show else None

        a = QPropertyAnimation(w, b"geometry", w)
        a.setDuration(ms)
        a.setStartValue(start_geo)
        a.setEndValue(end_geo)
        a.setEasingCurve(Easing.SLIDE_OPEN if show else Easing.SLIDE_CLOSE)
        a.finished.connect(lambda: setattr(self, '_anim', None))
        if on_done:
            a.finished.connect(on_done)
        if not show:
            a.finished.connect(w.hide)
        self._anim = a
        a.start(QAbstractAnimation.DeletionPolicy.DeleteWhenStopped)


# ══════════════════════════════════════════════════════════════════════════════
# WORKER / THREAD POOL  —  safe non-blocking background tasks
# ══════════════════════════════════════════════════════════════════════════════

class WorkerSignals(QObject):
    """Signals emitted by Worker back to the GUI thread."""
    result   = Signal(object)   # any result payload
    error    = Signal(str)      # error message string
    progress = Signal(int)      # 0-100 progress value
    finished = Signal()         # always emitted last


class Worker(QRunnable):
    """
    Generic background worker.  Use for any network / IO operation.

    Usage:
        def my_task(progress_fn):
            result = do_work()
            return result

        worker = Worker(my_task)
        worker.signals.result.connect(handle_result)
        worker.signals.error.connect(handle_error)
        QThreadPool.globalInstance().start(worker)
    """

    def __init__(self, fn: Callable, *args: Any, **kwargs: Any) -> None:
        super().__init__()
        self.fn     = fn
        self.args   = args
        self.kwargs = kwargs
        self.signals = WorkerSignals()
        self.setAutoDelete(True)

    @Slot()
    def run(self) -> None:
        try:
            result = self.fn(
                *self.args,
                progress=self.signals.progress,
                **self.kwargs,
            )
        except TypeError:
            # fn doesn't accept progress kwarg — call without it
            try:
                result = self.fn(*self.args, **self.kwargs)
            except Exception as exc:
                self.signals.error.emit(str(exc))
                self.signals.finished.emit()
                return
        except Exception as exc:
            self.signals.error.emit(str(exc))
            self.signals.finished.emit()
            return
        self.signals.result.emit(result)
        self.signals.finished.emit()


def run_async(fn: Callable, *args: Any,
              on_result: Optional[Callable]  = None,
              on_error:  Optional[Callable]  = None,
              on_done:   Optional[Callable]  = None,
              **kwargs: Any) -> Worker:
    """
    Convenience: submit a callable to the global QThreadPool.
    Returns the Worker so callers can connect additional signals if needed.
    """
    worker = Worker(fn, *args, **kwargs)
    if on_result: worker.signals.result.connect(on_result)
    if on_error:  worker.signals.error.connect(on_error)
    if on_done:   worker.signals.finished.connect(on_done)
    QThreadPool.globalInstance().start(worker)
    return worker

# ══════════════════════════════════════════════════════════════════════════════
# HOTKEY MANAGER  —  global keyboard shortcut registry
# ══════════════════════════════════════════════════════════════════════════════

class HotkeyManager(QObject):
    """
    Manages named global shortcuts bound to a parent QMainWindow.
    Shortcuts are derived from  game.settings.hotkeys  (DEFAULT_HOTKEYS dict).
    Call  reload()  after any hotkey remapping to rebuild all QShortcuts.
    """

    triggered = Signal(str)  # emits the action name

    def __init__(self, parent: "GameApp") -> None:
        super().__init__(parent)
        self._parent   = parent
        self._shortcuts: Dict[str, QShortcut] = {}

    def reload(self, hotkeys: Dict[str, str]) -> None:
        """Destroy all existing shortcuts and rebuild from  hotkeys  dict."""
        for sc in self._shortcuts.values():
            sc.setEnabled(False)
            sc.deleteLater()
        self._shortcuts.clear()

        for action, binding in hotkeys.items():
            key_seq = self._parse(binding)
            if not key_seq:
                continue
            sc = QShortcut(key_seq, self._parent)
            sc.setContext(Qt.ShortcutContext.ApplicationShortcut)
            # Capture action name in closure
            sc.activated.connect(lambda a=action: self.triggered.emit(a))
            self._shortcuts[action] = sc

    def set_enabled(self, enabled: bool) -> None:
        """Enable or disable all managed shortcuts (e.g., during hotkey capture)."""
        for sc in self._shortcuts.values():
            sc.setEnabled(enabled)

    @staticmethod
    def _parse(binding: str) -> Optional[QKeySequence]:
        """Convert e.g. 'Control-s' or 'F10' or 't' to QKeySequence."""
        if not binding:
            return None
        # Tkinter-style modifiers → Qt-style
        binding = (binding
                   .replace("Control-", "Ctrl+")
                   .replace("Shift-",   "Shift+")
                   .replace("Alt-",     "Alt+"))
        ks = QKeySequence(binding)
        return ks if not ks.isEmpty() else None

# ══════════════════════════════════════════════════════════════════════════════
# SCREEN BASE CLASS
# ══════════════════════════════════════════════════════════════════════════════

class Screen(QWidget):
    """
    Base class for every game screen.

    Lifecycle (called by GameApp.show()):
        build()    — create all widgets; called exactly once on first show
        refresh()  — pull current game state into widgets; called on every show
        on_show()  — hook called each time this screen becomes active
        on_hide()  — hook called each time this screen is concealed

    Convenience helpers:
        self.app          → GameApp
        self.game         → Game model
        self.msg          → MessageBar  (ok / warn / err)

    Layout helpers:
        self.section_label(text)        → gold divider label
        self.action_button(text, fn)    → standard primary button
        self.back_button(text)          → back-navigation button
        self.colored_label(text, color) → label with explicit colour
        self.h_sep()                    → horizontal separator line
    """

    def __init__(self, app: "GameApp") -> None:
        parent = app.content_stack
        super().__init__(parent)
        self.app    = app
        self.game   = app.game
        self.msg    = app.message_bar
        self._built = False
        self._fade  = FadeEffect(self)

        self.setObjectName("screen")
        self.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Expanding)

    # ── Lifecycle ─────────────────────────────────────────────────────────────

    def activate(self) -> None:
        """Called by GameApp to make this screen visible."""
        if not self._built:
            self.build()
            self._built = True
        self.refresh()
        self.on_show()
        self._fade.fade_in(220)

    def deactivate(self) -> None:
        """Called by GameApp to hide this screen."""
        self.on_hide()

    def rebuild(self) -> None:
        """
        Destroy all built child widgets and re-run build() + refresh() at the
        current UI scale.  Safe to call while the screen is active.
        """
        for child in list(self.children()):
            if isinstance(child, QTimer):
                child.stop()
                child.setParent(None)
                child.deleteLater()
            elif isinstance(child, QWidget):
                child.setParent(None)
                child.deleteLater()
        self._built = False
        self.build()
        self._built = True
        self.refresh()
        self.update()

    # ── Subclass API ──────────────────────────────────────────────────────────

    def build(self) -> None:
        """Override: create all widgets here.  Called exactly once."""
        pass

    def refresh(self) -> None:
        """Override: update widget values from current game state."""
        pass

    def on_show(self) -> None:
        """Override: runs each time this screen becomes the active screen."""
        pass

    def on_hide(self) -> None:
        """Override: runs each time this screen is concealed."""
        pass

    # ── Widget factory helpers ────────────────────────────────────────────────

    def section_label(self, text: str, parent: Optional[QWidget] = None) -> QLabel:
        lbl = QLabel(f"  {Sym.SECTION}  {text.upper()}  {Sym.SECTION}", parent or self)
        lbl.setFont(Fonts.mixed_bold)
        lbl.setProperty("role", "section")
        lbl.setStyleSheet(f"color: {P.gold}; padding: 4px 0px;")
        return lbl

    def action_button(self, text: str, command: Callable,
                      parent: Optional[QWidget] = None,
                      role: str = "primary") -> "MtButton":
        btn = MtButton(text, parent or self, role=role)
        btn.clicked.connect(command)
        return btn

    def back_button(self, text: str = f"{Sym.BACK}  Back",
                    parent: Optional[QWidget] = None) -> "MtButton":
        btn = MtButton(text, parent or self, role="nav")
        btn.clicked.connect(self.app.go_back)
        return btn

    def colored_label(self, text: str, color: str,
                      font: Optional[QFont] = None,
                      parent: Optional[QWidget] = None) -> QLabel:
        lbl = QLabel(text, parent or self)
        lbl.setFont(font or Fonts.body)
        lbl.setStyleSheet(f"color: {color}; background: transparent;")
        return lbl

    def h_sep(self, parent: Optional[QWidget] = None) -> QFrame:
        line = QFrame(parent or self)
        line.setFrameShape(QFrame.Shape.HLine)
        line.setStyleSheet(f"color: {P.border}; background-color: {P.border};")
        line.setFixedHeight(1)
        return line

    def make_panel(self, parent: Optional[QWidget] = None,
                   object_name: str = "panel") -> QFrame:
        """A styled panel frame."""
        f = QFrame(parent or self)
        f.setObjectName(object_name)
        f.setProperty("class", object_name)
        return f

# ══════════════════════════════════════════════════════════════════════════════
# MT BUTTON  —  custom QPushButton with press animation
# ══════════════════════════════════════════════════════════════════════════════

class MtButton(QPushButton):
    """
    Standard Merchant Tycoon button.
    Adds a brief opacity-dip press animation and correct role styling.
    Hover effects are handled entirely by QSS (border-color + bg change).
    """

    def __init__(self, text: str = "",
                 parent: Optional[QWidget] = None,
                 role: str = "primary",
                 icon: Optional[QIcon] = None) -> None:
        super().__init__(text, parent)
        self.setProperty("role", role)
        if icon:
            self.setIcon(icon)
        self.setFont(Fonts.mixed_bold)
        self.setCursor(QCursor(Qt.CursorShape.PointingHandCursor))
        self.setSizePolicy(QSizePolicy.Policy.Preferred, QSizePolicy.Policy.Fixed)
        self._press_anim: Optional[QPropertyAnimation] = None
        self._opacity_eff: Optional[QGraphicsOpacityEffect] = None

    def setRole(self, role: str) -> None:
        self.setProperty("role", role)
        self.style().unpolish(self)
        self.style().polish(self)

    def mousePressEvent(self, event: QMouseEvent) -> None:
        if event.button() == Qt.MouseButton.LeftButton:
            eff = QGraphicsOpacityEffect(self)
            eff.setOpacity(1.0)
            self.setGraphicsEffect(eff)
            self._opacity_eff = eff
            anim = QPropertyAnimation(eff, b"opacity", self)
            anim.setDuration(80)
            anim.setStartValue(1.0)
            anim.setEndValue(0.6)
            anim.setEasingCurve(Easing.BUTTON_PRESS)
            self._press_anim = anim
            anim.start(QAbstractAnimation.DeletionPolicy.DeleteWhenStopped)
        super().mousePressEvent(event)

    def mouseReleaseEvent(self, event: QMouseEvent) -> None:
        if self._opacity_eff is not None:
            anim = QPropertyAnimation(self._opacity_eff, b"opacity", self)
            anim.setDuration(120)
            anim.setStartValue(self._opacity_eff.opacity())
            anim.setEndValue(1.0)
            anim.setEasingCurve(Easing.BUTTON_RELEASE)
            anim.finished.connect(lambda: self.setGraphicsEffect(None))  # type: ignore[arg-type]
            self._press_anim = anim
            anim.start(QAbstractAnimation.DeletionPolicy.DeleteWhenStopped)
            self._opacity_eff = None
        super().mouseReleaseEvent(event)


class ProfileIconButton(QPushButton):
    """Circular header button with a simple bust glyph for profile access."""

    def __init__(self, parent: Optional[QWidget] = None) -> None:
        super().__init__("", parent)
        self._hovered = False
        self.setToolTip("Profile")
        self.setCursor(QCursor(Qt.CursorShape.PointingHandCursor))
        self.setFixedSize(UIScale.px(40), UIScale.px(34))
        self.setStyleSheet("QPushButton{background:transparent;border:none;padding:0px;}")

    def enterEvent(self, event) -> None:
        self._hovered = True
        self.update()
        super().enterEvent(event)

    def leaveEvent(self, event) -> None:
        self._hovered = False
        self.update()
        super().leaveEvent(event)

    def paintEvent(self, event) -> None:
        del event
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)

        outer = QRectF(self.rect()).adjusted(1.0, 1.0, -1.0, -1.0)
        hovered = self._hovered or self.isDown()
        bg = Palette.rgba(P.bg_hover if hovered else P.bg_panel, 220 if hovered else 170)
        border = QColor(P.gold if hovered else P.border)
        fg = QColor(P.gold if hovered else P.fg_dim)

        painter.setPen(QPen(border, 1.2))
        painter.setBrush(bg)
        painter.drawEllipse(outer)

        painter.setPen(QPen(fg, 1.8, Qt.PenStyle.SolidLine, Qt.PenCapStyle.RoundCap))
        painter.setBrush(Qt.BrushStyle.NoBrush)

        head = QRectF(
            outer.center().x() - outer.width() * 0.13,
            outer.top() + outer.height() * 0.22,
            outer.width() * 0.26,
            outer.height() * 0.26,
        )
        painter.drawEllipse(head)

        shoulders = QRectF(
            outer.center().x() - outer.width() * 0.26,
            outer.top() + outer.height() * 0.46,
            outer.width() * 0.52,
            outer.height() * 0.28,
        )
        painter.drawArc(shoulders, 25 * 16, 130 * 16)

# ══════════════════════════════════════════════════════════════════════════════
# STATUS BAR  —  persistent HUD strip
# ══════════════════════════════════════════════════════════════════════════════

class StatusBar(QWidget):
    """
    Persistent top strip — always visible, refreshed after every action.
    Displays: player name, title, date/season, gold, bank, location,
              net worth, action slots, heat, active events.
    """

    def __init__(self, game: Game, parent: Optional[QWidget] = None) -> None:
        super().__init__(parent)
        self.game = game
        self._prev_gold: float = -1.0
        self.setObjectName("statusBar")
        self.setFixedHeight(UIScale.px(90))
        self.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Fixed)
        self.setStyleSheet(f"""
            #statusBar {{
                background-color: {P.bg_panel};
                border-bottom: 2px solid {P.border_light};
            }}
        """)
        self._build()

    # ── Private build ─────────────────────────────────────────────────────────

    def _mk_label(self, text: str = "", font: Optional[QFont] = None,
                  colour: str = P.fg) -> QLabel:
        lbl = QLabel(text, self)
        lbl.setFont(font or Fonts.body)
        lbl.setStyleSheet(f"color: {colour}; background: transparent;")
        return lbl

    def _build(self) -> None:
        root = QVBoxLayout(self)
        root.setContentsMargins(UIScale.px(10), UIScale.px(4),
                                UIScale.px(10), UIScale.px(4))
        root.setSpacing(UIScale.px(2))

        # Row 1: player name · date/season · reputation
        r1 = QHBoxLayout()
        r1.setSpacing(UIScale.px(12))
        self._player   = self._mk_label(font=Fonts.body_bold, colour=P.fg_dim)
        self._title_lbl = self._mk_label(font=Fonts.body_small, colour=P.gold)
        self._date     = self._mk_label(font=Fonts.body_small, colour=P.fg_dim)
        self._rep      = self._mk_label(font=Fonts.body_small, colour=P.green)
        r1.addWidget(self._player)
        r1.addWidget(self._title_lbl)
        r1.addSpacing(UIScale.px(6))
        r1.addWidget(self._date)
        r1.addStretch()
        r1.addWidget(self._rep)

        # Row 2: gold / bank / location / net worth
        r2 = QHBoxLayout()
        r2.setSpacing(UIScale.px(12))
        self._gold     = self._mk_label(font=Fonts.body_bold, colour=P.amber)
        self._location = self._mk_label(font=Fonts.body,      colour=P.gold)
        self._nw       = self._mk_label(font=Fonts.body_small, colour=P.fg_dim)
        r2.addWidget(self._gold)
        r2.addSpacing(UIScale.px(6))
        r2.addWidget(self._location)
        r2.addStretch()
        r2.addWidget(self._nw)

        # Row 3: action slots · heat · events
        r3 = QHBoxLayout()
        r3.setSpacing(UIScale.px(12))
        self._slots  = self._mk_label(font=Fonts.body_small, colour=P.gold)
        self._heat   = self._mk_label(font=Fonts.body_small, colour=P.red)
        self._events = self._mk_label(font=Fonts.body_small, colour=P.amber)
        r3.addWidget(self._slots)
        r3.addWidget(self._heat)
        r3.addWidget(self._events)
        r3.addStretch()

        root.addLayout(r1)
        root.addLayout(r2)
        root.addLayout(r3)

        # Gold flash effect
        self._gold_fade = FadeEffect(self._gold)

    # ── Public refresh ────────────────────────────────────────────────────────

    def refresh(self) -> None:
        g = self.game

        # Player name + active title
        name = g.player_name or "Merchant"
        self._player.setText(f"{Sym.PLAYER}  {name}")
        active_title = getattr(g, "active_title_id", None)
        title_text   = ""
        if active_title and active_title in TITLES_BY_ID:
            title_text = f"〔{TITLES_BY_ID[active_title]['name']}〕"
        self._title_lbl.setText(title_text)

        # Date / season
        season_col = SEASON_COLOURS.get(g.season, P.fg)
        self._date.setText(f"Year {g.year}  ·  Day {g.day}  ·  {g.season.value}")
        self._date.setStyleSheet(f"color: {season_col}; background: transparent;")

        # Reputation
        rep_lbl_text, rep_col = rep_label(g.reputation)
        self._rep.setText(f"Rep: {g.reputation}  ({rep_lbl_text})")
        self._rep.setStyleSheet(f"color: {rep_col}; background: transparent;")

        # Gold (with flash on change)
        new_gold = g.inventory.gold
        self._gold.setText(f"{Sym.GOLD} {new_gold:,.0f}g   Bank: {g.bank_balance:,.0f}g")
        if self._prev_gold >= 0 and new_gold != self._prev_gold:
            flash_col = P.green if new_gold > self._prev_gold else P.red
            self._flash_gold(flash_col)
        self._prev_gold = new_gold

        # Location
        self._location.setText(f"{Sym.LOCATION}  {g.current_area.value}")

        # Net worth
        self._nw.setText(f"Net Worth: {g._net_worth():,.2f}g")

        # Action slots
        used = g.daily_time_units
        left = g.DAILY_TIME_UNITS - used
        bar  = "●" * used + "○" * left
        slot_col = P.red if left == 0 else P.amber if left <= 2 else P.gold
        self._slots.setText(f"{Sym.SLOT_FULL} {bar}  ({left} actions left)")
        self._slots.setStyleSheet(f"color: {slot_col}; background: transparent;")

        # Heat
        if g.heat > 0:
            heat_col = P.red if g.heat > 50 else P.amber
            self._heat.setText(f"{Sym.HEAT} Heat: {g.heat}/100")
            self._heat.setStyleSheet(f"color: {heat_col}; background: transparent;")
        else:
            self._heat.setText("")

        # Active events
        events: List[str] = []
        for mkt in g.markets.values():
            events.extend(mkt.active_events)
        if events:
            unique = list(dict.fromkeys(events))[:3]
            self._events.setText("Events: " + "  ·  ".join(unique))
        else:
            self._events.setText("")

    def _flash_gold(self, colour: str) -> None:
        """Brief colour flash on gold label when value changes."""
        self._gold.setStyleSheet(f"color: {colour}; background: transparent;")
        QTimer.singleShot(600, lambda: self._gold.setStyleSheet(
            f"color: {P.amber}; background: transparent;"))


# ══════════════════════════════════════════════════════════════════════════════
# MESSAGE BAR  —  bottom feedback strip
# ══════════════════════════════════════════════════════════════════════════════

class MessageBar(QWidget):
    """
    Slim bottom strip for user feedback.
    Messages animate in (height expand), auto-clear after _CLEAR_MS.
    Severity: ok (green) / warn (amber) / err (red) / info (gold).
    """

    _CLEAR_MS   = 9_000
    _TARGET_H   = UIScale.px(44)

    def __init__(self, parent: Optional[QWidget] = None) -> None:
        super().__init__(parent)
        self.setObjectName("messageBar")
        self.setFixedHeight(0)  # hidden initially
        self.setStyleSheet(f"""
            #messageBar {{
                background-color: {P.bg_panel};
                border-top: 1px solid {P.border};
            }}
        """)

        layout = QHBoxLayout(self)
        layout.setContentsMargins(UIScale.px(12), 0, UIScale.px(12), 0)
        self._label = QLabel("", self)
        self._label.setFont(Fonts.mixed_bold)
        self._label.setStyleSheet("background: transparent;")
        layout.addWidget(self._label)

        self._clear_timer = QTimer(self)
        self._clear_timer.setSingleShot(True)
        self._clear_timer.timeout.connect(self._clear)

        self._anim = QPropertyAnimation(self, b"maximumHeight", self)
        self._anim.setEasingCurve(Easing.SMOOTH)

        self._toast_fn: Optional[Callable] = None   # set by GameApp

    # ── Public API ────────────────────────────────────────────────────────────

    def ok(self,   text: str) -> None: self._show(f"  {Sym.YES}  {text}", P.green)
    def warn(self, text: str) -> None: self._show(f"  {Sym.WARNING}  {text}", P.amber)
    def err(self,  text: str) -> None: self._show(f"  {Sym.NO}  {text}", P.red)
    def info(self, text: str) -> None: self._show(f"  {Sym.INFO}  {text}", P.gold)

    # ── Private ───────────────────────────────────────────────────────────────

    def _show(self, text: str, colour: str) -> None:
        # When a floating toast handler is available, relay to it and keep the
        # message bar invisible (single notification, not two stacked displays).
        if self._toast_fn:
            try:
                self._toast_fn(text.strip().lstrip("\u2714\u26a0\u2718\u203a  "), colour)
            except Exception:
                pass
            return

        self._label.setText(text)
        self._label.setStyleSheet(f"color: {colour}; background: transparent;")

        if self._anim.state() == QAbstractAnimation.State.Running:
            self._anim.stop()

        self._anim.setDuration(120)
        self._anim.setStartValue(self.height())
        self._anim.setEndValue(self._TARGET_H)
        self.setMaximumHeight(self.height())
        self.setMinimumHeight(0)
        self._anim.start()

        self._clear_timer.start(self._CLEAR_MS)

    def _clear(self) -> None:
        if self._anim.state() == QAbstractAnimation.State.Running:
            self._anim.stop()
        self._anim.setDuration(180)
        self._anim.setStartValue(self.height())
        self._anim.setEndValue(0)
        self._anim.start()
        self._label.setText("")


# ══════════════════════════════════════════════════════════════════════════════
# GAME TOAST  —  floating transient notification overlay
# Shared registry for ALL floating notifications (GameToast + FloatingStatNotice).
# Using a single list ensures they don't overlap each other regardless of type.
_NOTIFICATION_ACTIVE: List = []   # module-level; items are either GameToast or FloatingStatNotice


# ══════════════════════════════════════════════════════════════════════════════

class GameToast(QWidget):
    """
    Small floating notification that slides up from the bottom-right,
    lingers, then fades out.  Does not steal focus.
    """

    _DURATION_MS  = 5_000
    _SLIDE_IN_MS  = 280
    _FADE_OUT_MS  = 500
    _MAX_VISIBLE  = 6   # shared stack limit
    _STACK_MARGIN = 16

    _active: List["GameToast"] = []   # kept for back-compat; real list is _NOTIFICATION_ACTIVE

    def __init__(self, parent: QWidget, text: str,
                 colour: str = P.amber,
                 duration_ms: Optional[int] = None) -> None:
        super().__init__(parent, Qt.WindowType.ToolTip)
        self._host = parent
        self._duration_ms = duration_ms or self._DURATION_MS
        self.setAttribute(Qt.WidgetAttribute.WA_TransparentForMouseEvents)
        self.setAttribute(Qt.WidgetAttribute.WA_ShowWithoutActivating)
        self.setWindowFlags(Qt.WindowType.FramelessWindowHint |
                            Qt.WindowType.ToolTip |
                            Qt.WindowType.WindowStaysOnTopHint)

        # Limit shared stack size
        while len(self._shared_stack_for(parent)) >= self._MAX_VISIBLE:
            oldest = self._shared_stack_for(parent)[0]
            try:
                oldest._dismiss_now()
            except Exception:
                pass

        _NOTIFICATION_ACTIVE.append(self)
        GameToast._active.append(self)

        self.setStyleSheet(f"""
            QWidget {{
                background-color: {P.bg_dialog};
                border: 1px solid {colour};
                border-radius: 5px;
                padding: 4px 12px;
            }}
        """)

        layout = QHBoxLayout(self)
        layout.setContentsMargins(UIScale.px(12), UIScale.px(6),
                                  UIScale.px(12), UIScale.px(6))
        lbl = QLabel(text, self)
        lbl.setFont(Fonts.body_small)
        lbl.setStyleSheet(f"color: {colour}; background: transparent; border: none;")
        lbl.setWordWrap(True)
        lbl.setMaximumWidth(UIScale.px(380))
        layout.addWidget(lbl)

        self.adjustSize()

        start_pos, end_pos = self._positions_for(parent)

        self.move(start_pos)
        self.show()

        self._reflow(parent, exclude=self)

        # Slide in
        self._pos_anim = QPropertyAnimation(self, b"pos", self)
        self._pos_anim.setDuration(self._SLIDE_IN_MS)
        self._pos_anim.setStartValue(start_pos)
        self._pos_anim.setEndValue(end_pos)
        self._pos_anim.setEasingCurve(Easing.TOAST_IN)
        self._pos_anim.start(QAbstractAnimation.DeletionPolicy.DeleteWhenStopped)

        # Auto-dismiss
        QTimer.singleShot(self._duration_ms, self._start_fade_out)

    @classmethod
    def _shared_stack_for(cls, parent: QWidget) -> list:
        return [n for n in _NOTIFICATION_ACTIVE
                if getattr(n, "_host", None) is parent and not n.isHidden()]

    @classmethod
    def _stack_for(cls, parent: QWidget) -> List["GameToast"]:
        return [n for n in _NOTIFICATION_ACTIVE
                if getattr(n, "_host", None) is parent and not n.isHidden()]

    @classmethod
    def _target_pos(cls, parent: QWidget, item: QWidget, index: int) -> QPoint:
        margin = UIScale.px(cls._STACK_MARGIN)
        pgeom = parent.rect()
        origin = parent.mapToGlobal(QPoint(0, 0))
        x = origin.x() + pgeom.width() - item.width() - margin
        y = origin.y() + pgeom.height() - margin - (item.height() + margin) * (index + 1)
        return QPoint(x, y)

    def _positions_for(self, parent: QWidget) -> Tuple[QPoint, QPoint]:
        stack = self._shared_stack_for(parent)
        idx = max(0, len(stack) - 1)
        end_pos = self._target_pos(parent, self, idx)
        origin = parent.mapToGlobal(QPoint(0, 0))
        start_pos = QPoint(end_pos.x(), origin.y() + parent.height())
        return start_pos, end_pos

    @classmethod
    def _reflow(cls, parent: QWidget, exclude: Optional[QWidget] = None) -> None:
        for idx, item in enumerate(cls._shared_stack_for(parent)):
            if item is exclude:
                continue
            item.move(cls._target_pos(parent, item, idx))

    @classmethod
    def reflow_for(cls, parent: QWidget) -> None:
        cls._reflow(parent)

    def _start_fade_out(self) -> None:
        if self.graphicsEffect() is not None:
            return
        self._opacity_eff = QGraphicsOpacityEffect(self)
        self.setGraphicsEffect(self._opacity_eff)
        self._fade_anim = QPropertyAnimation(self._opacity_eff, b"opacity", self)
        self._fade_anim.setDuration(self._FADE_OUT_MS)
        self._fade_anim.setStartValue(1.0)
        self._fade_anim.setEndValue(0.0)
        self._fade_anim.setEasingCurve(Easing.TOAST_OUT)
        self._fade_anim.finished.connect(self._dismiss_now)
        self._fade_anim.start(QAbstractAnimation.DeletionPolicy.DeleteWhenStopped)

    def _dismiss_now(self) -> None:
        try:
            _NOTIFICATION_ACTIVE.remove(self)
        except ValueError:
            pass
        try:
            GameToast._active.remove(self)
        except ValueError:
            pass
        host = getattr(self, "_host", None)
        self.hide()
        self.deleteLater()
        if host is not None:
            self._reflow(host)


class FloatingStatNotice(QWidget):
    """Fleeting stat-delta notifier.  Shares the unified bottom-right toast stack."""

    _DURATION_MS = 1_800
    _FADE_IN_MS = 140
    _FLOAT_MS = 500
    _FADE_OUT_MS = 320
    _STACK_MARGIN = 16
    _MAX_VISIBLE = 6   # shared with GameToast

    _active: List["FloatingStatNotice"] = []   # kept for back-compat

    def __init__(self, parent: QWidget, text: str, colour: str) -> None:
        super().__init__(parent, Qt.WindowType.ToolTip)
        self._host = parent
        self.setAttribute(Qt.WidgetAttribute.WA_TransparentForMouseEvents)
        self.setAttribute(Qt.WidgetAttribute.WA_ShowWithoutActivating)
        self.setWindowFlags(
            Qt.WindowType.FramelessWindowHint |
            Qt.WindowType.ToolTip |
            Qt.WindowType.WindowStaysOnTopHint
        )

        while len(self._stack_for(parent)) >= self._MAX_VISIBLE:
            oldest = self._stack_for(parent)[0]
            try:
                oldest._dismiss_now()
            except Exception:
                pass

        # Limit shared stack size
        while len(self._shared_stack_for(parent)) >= self._MAX_VISIBLE:
            oldest = self._shared_stack_for(parent)[0]
            try:
                oldest._dismiss_now()
            except Exception:
                pass

        _NOTIFICATION_ACTIVE.append(self)
        FloatingStatNotice._active.append(self)
        self.setStyleSheet(
            f"QWidget{{background-color:{P.bg_dialog}; border:1px solid {colour}; border-radius:8px;}}"
        )

        layout = QHBoxLayout(self)
        layout.setContentsMargins(UIScale.px(12), UIScale.px(7), UIScale.px(12), UIScale.px(7))
        lbl = QLabel(text, self)
        lbl.setFont(Fonts.mixed_small_bold)
        lbl.setStyleSheet(f"color:{colour}; background:transparent; border:none;")
        layout.addWidget(lbl)

        self.adjustSize()

        self._opacity = QGraphicsOpacityEffect(self)
        self._opacity.setOpacity(0.0)
        self.setGraphicsEffect(self._opacity)

        start_pos, end_pos = self._positions_for(parent)
        self.move(start_pos)
        self.show()
        GameToast._reflow(parent, exclude=self)   # reflow the shared stack

        self._fade_in = QPropertyAnimation(self._opacity, b"opacity", self)
        self._fade_in.setDuration(self._FADE_IN_MS)
        self._fade_in.setStartValue(0.0)
        self._fade_in.setEndValue(1.0)
        self._fade_in.setEasingCurve(Easing.SMOOTH)
        self._fade_in.start(QAbstractAnimation.DeletionPolicy.DeleteWhenStopped)

        self._rise_in = QPropertyAnimation(self, b"pos", self)
        self._rise_in.setDuration(self._FLOAT_MS)
        self._rise_in.setStartValue(start_pos)
        self._rise_in.setEndValue(end_pos)
        self._rise_in.setEasingCurve(Easing.TOAST_IN)
        self._rise_in.start(QAbstractAnimation.DeletionPolicy.DeleteWhenStopped)

        QTimer.singleShot(self._DURATION_MS, self._start_exit)

    @classmethod
    def _shared_stack_for(cls, parent: QWidget) -> list:
        return [n for n in _NOTIFICATION_ACTIVE
                if getattr(n, "_host", None) is parent and not n.isHidden()]

    @classmethod
    def _stack_for(cls, parent: QWidget) -> List["FloatingStatNotice"]:
        return [n for n in _NOTIFICATION_ACTIVE
                if getattr(n, "_host", None) is parent and not n.isHidden()]

    @classmethod
    def _target_pos(cls, parent: QWidget, item: QWidget, index: int) -> QPoint:
        margin = UIScale.px(cls._STACK_MARGIN)
        pgeom = parent.rect()
        origin = parent.mapToGlobal(QPoint(0, 0))
        x = origin.x() + pgeom.width() - item.width() - margin
        y = origin.y() + pgeom.height() - margin - (item.height() + margin) * (index + 1)
        return QPoint(x, y)

    def _positions_for(self, parent: QWidget) -> Tuple[QPoint, QPoint]:
        stack = self._shared_stack_for(parent)
        idx = max(0, len(stack) - 1)
        end_pos = self._target_pos(parent, self, idx)
        origin = parent.mapToGlobal(QPoint(0, 0))
        start_pos = QPoint(end_pos.x(), origin.y() + parent.height())
        return start_pos, end_pos

    @classmethod
    def _reflow(cls, parent: QWidget, exclude: Optional[QWidget] = None) -> None:
        GameToast._reflow(parent, exclude=exclude)

    @classmethod
    def reflow_for(cls, parent: QWidget) -> None:
        GameToast._reflow(parent)

    def _start_exit(self) -> None:
        self._exit_group = QParallelAnimationGroup(self)

        fade = QPropertyAnimation(self._opacity, b"opacity", self)
        fade.setDuration(self._FADE_OUT_MS)
        fade.setStartValue(1.0)
        fade.setEndValue(0.0)
        fade.setEasingCurve(Easing.VALUE_FADE)

        self._exit_group.addAnimation(fade)
        self._exit_group.finished.connect(self._dismiss_now)
        self._exit_group.start(QAbstractAnimation.DeletionPolicy.DeleteWhenStopped)

    def _dismiss_now(self) -> None:
        try:
            _NOTIFICATION_ACTIVE.remove(self)
        except ValueError:
            pass
        try:
            FloatingStatNotice._active.remove(self)
        except ValueError:
            pass
        host = getattr(self, "_host", None)
        self.hide()
        self.deleteLater()
        if host is not None:
            GameToast._reflow(host)


class AnimatedValueLabel(QLabel):
    """Numeric HUD label with roll-up and pop animation."""

    def __init__(self, parent: Optional[QWidget] = None, *, colour: str = "") -> None:
        super().__init__(parent)
        self._base_colour = colour or P.fg
        self._draw_colour = self._base_colour
        self._display_value = 0.0
        self._target_value = 0.0
        self._pulse_scale = 1.0
        self._formatter: Callable[[float], str] = lambda value: str(value)
        self._colourer: Optional[Callable[[float], str]] = None
        self._value_anim: Optional[QPropertyAnimation] = None
        self._pulse_anim: Optional[QSequentialAnimationGroup] = None
        self._initialized = False
        self.setAttribute(Qt.WidgetAttribute.WA_TranslucentBackground)

    def set_formatter(
        self,
        formatter: Callable[[float], str],
        *,
        colourer: Optional[Callable[[float], str]] = None,
    ) -> None:
        self._formatter = formatter
        self._colourer = colourer
        self._sync_text()

    def _get_display_value(self) -> float:
        return self._display_value

    def _set_display_value(self, value: float) -> None:
        self._display_value = float(value)
        self._sync_text()

    displayValue = QtProperty(float, _get_display_value, _set_display_value)

    def _get_pulse_scale(self) -> float:
        return self._pulse_scale

    def _set_pulse_scale(self, value: float) -> None:
        self._pulse_scale = float(value)
        self.update()

    pulseScale = QtProperty(float, _get_pulse_scale, _set_pulse_scale)

    def _clear_value_anim_ref(self) -> None:
        self._value_anim = None

    def _clear_pulse_anim_ref(self) -> None:
        self._pulse_anim = None

    def _stop_value_animation(self) -> None:
        anim = self._value_anim
        self._value_anim = None
        if anim is None:
            return
        try:
            anim.stop()
        except RuntimeError:
            return
        anim.deleteLater()

    def _stop_pulse_animation(self) -> None:
        anim = self._pulse_anim
        self._pulse_anim = None
        if anim is None:
            return
        try:
            anim.stop()
        except RuntimeError:
            return
        anim.deleteLater()

    def set_animated_value(self, value: float, *, animate: bool = True, emphasize: bool = False) -> None:
        target = float(value)
        previous = self._target_value
        self._target_value = target
        if not self._initialized or not animate:
            self._initialized = True
            self._display_value = target
            self._pulse_scale = 1.0
            self._sync_text()
            self.update()
            return
        self._stop_value_animation()
        anim = QPropertyAnimation(self, b"displayValue", self)
        anim.setDuration(760)
        anim.setStartValue(self._display_value)
        anim.setEndValue(target)
        anim.setEasingCurve(QEasingCurve.Type.OutCubic)
        anim.finished.connect(self._clear_value_anim_ref)
        self._value_anim = anim
        anim.start()
        if emphasize and target > previous:
            self._start_pulse()

    def _start_pulse(self) -> None:
        self._stop_pulse_animation()
        pulse = QSequentialAnimationGroup(self)
        grow = QPropertyAnimation(self, b"pulseScale", self)
        grow.setDuration(170)
        grow.setStartValue(max(1.0, self._pulse_scale))
        grow.setEndValue(1.16)
        grow.setEasingCurve(Easing.VALUE_POP)
        settle = QPropertyAnimation(self, b"pulseScale", self)
        settle.setDuration(280)
        settle.setStartValue(1.16)
        settle.setEndValue(1.0)
        settle.setEasingCurve(Easing.SMOOTH)
        pulse.addAnimation(grow)
        pulse.addAnimation(settle)
        pulse.finished.connect(self._clear_pulse_anim_ref)
        self._pulse_anim = pulse
        pulse.start()

    def _sync_text(self) -> None:
        self.setText(self._formatter(self._display_value))
        self._draw_colour = self._colourer(self._display_value) if self._colourer is not None else self._base_colour
        self.update()

    def paintEvent(self, event) -> None:
        del event
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)
        painter.setRenderHint(QPainter.RenderHint.TextAntialiasing, True)
        center = self.rect().center()
        painter.translate(center)
        painter.scale(self._pulse_scale, self._pulse_scale)
        painter.translate(-center)
        painter.setPen(QColor(self._draw_colour))
        painter.setFont(self.font())
        painter.drawText(self.rect(), int(self.alignment()), self.text())


class DelayedTooltipFilter(QObject):
    """Shows tooltips after a deliberate hover delay instead of immediately."""

    def __init__(self, parent: QObject, delay_ms: int = 1000) -> None:
        super().__init__(parent)
        self._delay_ms = max(250, int(delay_ms))
        self._timer = QTimer(self)
        self._timer.setSingleShot(True)
        self._timer.timeout.connect(self._show_tooltip)
        self._widget_ref: Optional[weakref.ReferenceType[QWidget]] = None
        self._text = ""

    def eventFilter(self, obj: QObject, event: QEvent) -> bool:
        widget = obj if isinstance(obj, QWidget) else None
        etype = event.type()
        if etype == QEvent.Type.ToolTip and widget is not None:
            return True
        if etype in {QEvent.Type.Enter, QEvent.Type.HoverEnter, QEvent.Type.MouseMove, QEvent.Type.HoverMove}:
            if widget is not None:
                self._schedule(widget)
        elif etype in {
            QEvent.Type.Leave,
            QEvent.Type.HoverLeave,
            QEvent.Type.Hide,
            QEvent.Type.FocusOut,
            QEvent.Type.MouseButtonPress,
            QEvent.Type.WindowDeactivate,
        }:
            self._clear()
        return False

    def _schedule(self, widget: QWidget) -> None:
        text = self._tooltip_text(widget)
        if not text:
            self._clear()
            return
        current = self._widget_ref() if self._widget_ref is not None else None
        if current is widget and self._text == text and self._timer.isActive():
            return
        self._widget_ref = weakref.ref(widget)
        self._text = text
        self._timer.start(self._delay_ms)

    def _clear(self) -> None:
        self._timer.stop()
        self._widget_ref = None
        self._text = ""
        QToolTip.hideText()

    def _show_tooltip(self) -> None:
        widget = self._widget_ref() if self._widget_ref is not None else None
        if widget is None or not widget.isVisible() or not self._text:
            return
        pos = widget.mapToGlobal(QPoint(max(8, widget.width() // 2), widget.height()))
        QToolTip.showText(pos, self._text, widget)

    def _tooltip_text(self, widget: QWidget) -> str:
        text = widget.toolTip().strip()
        if text:
            return text
        if isinstance(widget, QAbstractButton):
            return widget.text().replace("&", " ").replace("  ", " ").strip()
        if isinstance(widget, QLineEdit):
            return widget.placeholderText().strip()
        if isinstance(widget, QComboBox):
            return widget.currentText().strip()
        return ""


class VoyageProgressPanel(QWidget):
    """Compact animated voyage progress display for the dashboard."""

    def __init__(self, parent: Optional[QWidget] = None) -> None:
        super().__init__(parent)
        self._rows: List[Dict[str, Any]] = []
        self._phase = 0.0
        self.setMinimumHeight(UIScale.px(112))
        self.setMaximumHeight(UIScale.px(220))
        self._timer = QTimer(self)
        self._timer.setInterval(90)
        self._timer.timeout.connect(self._advance_phase)

    def set_voyages(self, voyages: List[Dict[str, Any]]) -> None:
        self._rows = list(voyages)
        sailing = any(row.get("status") == "sailing" for row in self._rows)
        if sailing and not self._timer.isActive():
            self._timer.start()
        if not sailing:
            self._timer.stop()
        self.update()

    def _advance_phase(self) -> None:
        self._phase = (self._phase + 0.18) % (math.pi * 2.0)
        self.update()

    def paintEvent(self, event) -> None:
        del event
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)
        painter.fillRect(self.rect(), Qt.GlobalColor.transparent)
        if not self._rows:
            painter.setPen(QColor(P.fg_dim))
            painter.setFont(Fonts.mixed_small)
            painter.drawText(self.rect(), int(Qt.AlignmentFlag.AlignCenter), "No voyages in motion.")
            return
        row_h = max(UIScale.px(34), self.height() // max(1, min(4, len(self._rows))))
        top = UIScale.px(6)
        for idx, row in enumerate(self._rows[:4]):
            y = top + idx * row_h
            self._paint_row(painter, QRect(0, y, self.width(), row_h - UIScale.px(2)), row, idx)

    def _paint_row(self, painter: QPainter, rect: QRect, row: Dict[str, Any], idx: int) -> None:
        status = str(row.get("status", "sailing") or "sailing")
        if status == "arrived":
            colour = P.green
        elif status.startswith("lost"):
            colour = P.red
        else:
            colour = P.gold
        title_rect = QRect(rect.left(), rect.top(), rect.width(), UIScale.px(14))
        painter.setPen(QColor(P.cream))
        painter.setFont(Fonts.tiny)
        painter.drawText(title_rect, int(Qt.AlignmentFlag.AlignLeft | Qt.AlignmentFlag.AlignVCenter), str(row.get("title", "Voyage")))
        painter.setPen(QColor(P.fg_dim))
        painter.drawText(title_rect, int(Qt.AlignmentFlag.AlignRight | Qt.AlignmentFlag.AlignVCenter), str(row.get("status_text", "")))

        track_y = rect.top() + UIScale.px(24)
        start_x = rect.left() + UIScale.px(10)
        end_x = rect.right() - UIScale.px(10)
        painter.setPen(QPen(QColor(P.border), UIScale.px(3), Qt.PenStyle.SolidLine, Qt.PenCapStyle.RoundCap))
        painter.drawLine(start_x, track_y, end_x, track_y)

        progress = max(0.0, min(1.0, float(row.get("progress", 0.0) or 0.0)))
        progress_x = start_x + int((end_x - start_x) * progress)
        painter.setPen(QPen(QColor(colour), UIScale.px(4), Qt.PenStyle.SolidLine, Qt.PenCapStyle.RoundCap))
        painter.drawLine(start_x, track_y, progress_x, track_y)

        painter.setBrush(QColor(P.border_light))
        painter.setPen(Qt.PenStyle.NoPen)
        painter.drawEllipse(QPoint(start_x, track_y), UIScale.px(3), UIScale.px(3))
        painter.drawEllipse(QPoint(end_x, track_y), UIScale.px(3), UIScale.px(3))

        ship_x = progress_x
        ship_y = track_y - UIScale.px(11)
        if status == "sailing":
            ship_y += int(math.sin(self._phase + idx * 0.8) * UIScale.px(2))
        painter.setPen(QColor(colour))
        painter.setFont(Fonts.mixed_small_bold)
        painter.drawText(QRect(ship_x - UIScale.px(10), ship_y, UIScale.px(20), UIScale.px(16)), int(Qt.AlignmentFlag.AlignCenter), Sym.VOYAGE)


class SecretPawButton(QWidget):
    clicked = Signal()

    def __init__(self, parent: Optional[QWidget] = None) -> None:
        super().__init__(parent)
        self._offset = 0.0
        self._anim: Optional[QSequentialAnimationGroup] = None
        self.setCursor(QCursor(Qt.CursorShape.PointingHandCursor))
        self.setToolTip("A faint paw print is pressed into the varnish.")
        self.setFixedSize(UIScale.px(28), UIScale.px(28))
        self._timer = QTimer(self)
        self._timer.setSingleShot(True)
        self._timer.timeout.connect(self._start_wiggle)
        self._schedule_wiggle()

    def _schedule_wiggle(self) -> None:
        self._timer.start(random.randint(6500, 12000))

    def _get_offset(self) -> float:
        return self._offset

    def _set_offset(self, value: float) -> None:
        self._offset = float(value)
        self.update()

    offset = QtProperty(float, _get_offset, _set_offset)

    def _start_wiggle(self) -> None:
        seq = QSequentialAnimationGroup(self)
        for end_value in (-2.0, 2.0, -1.5, 1.5, 0.0):
            anim = QPropertyAnimation(self, b"offset", seq)
            anim.setDuration(70)
            anim.setStartValue(self._offset)
            anim.setEndValue(end_value)
            anim.setEasingCurve(QEasingCurve.Type.InOutSine)
            seq.addAnimation(anim)
        seq.finished.connect(self._schedule_wiggle)
        self._anim = seq
        seq.start()

    def mouseReleaseEvent(self, event: QMouseEvent) -> None:
        pos = event.position().toPoint() if hasattr(event, "position") else event.pos()
        if event.button() == Qt.MouseButton.LeftButton and self.rect().contains(pos):
            self.clicked.emit()
        super().mouseReleaseEvent(event)

    def paintEvent(self, event) -> None:
        del event
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)
        painter.translate(self._offset, 0)
        rect = self.rect().adjusted(UIScale.px(2), UIScale.px(2), -UIScale.px(2), -UIScale.px(2))
        fill = QColor(P.bg_hover if self.underMouse() else P.bg_panel)
        fill.setAlpha(180 if self.underMouse() else 110)
        painter.setPen(QPen(QColor(P.border_light if self.underMouse() else P.border), 1))
        painter.setBrush(fill)
        painter.drawEllipse(rect)
        paw = _pawprint_pixmap(UIScale.px(14))
        if not paw.isNull():
            target = QRect(0, 0, paw.width(), paw.height())
            target.moveCenter(rect.center())
            painter.drawPixmap(target, paw)


_PAWPRINT_CACHE: Dict[Tuple[int, float], QPixmap] = {}


def _pawprint_pixmap(size: int, *, rotated: bool = False, angle: float = 0) -> QPixmap:
    size = max(8, int(size))
    effective_angle = float(angle) if angle else (90.0 if rotated else 0.0)
    cache_key = (size, effective_angle)
    cached = _PAWPRINT_CACHE.get(cache_key)
    if cached is not None:
        return cached
    pix = QPixmap(os.path.join(_HERE, "pawprint.png"))
    if pix.isNull():
        _PAWPRINT_CACHE[cache_key] = QPixmap()
        return _PAWPRINT_CACHE[cache_key]
    scaled = pix.scaled(size, size, Qt.AspectRatioMode.KeepAspectRatio,
                        Qt.TransformationMode.SmoothTransformation)
    if effective_angle:
        scaled = scaled.transformed(QTransform().rotate(effective_angle),
                                    Qt.TransformationMode.SmoothTransformation)
    _PAWPRINT_CACHE[cache_key] = scaled
    return scaled


class PawTrailWidget(QWidget):
    def __init__(self, parent: Optional[QWidget] = None, *, size: int = 18, compact: bool = False) -> None:
        super().__init__(parent)
        self._size = size
        self._compact = compact
        self.setMinimumHeight(UIScale.px(26 if compact else 34))
        self.setSizePolicy(QSizePolicy.Policy.Expanding, QSizePolicy.Policy.Fixed)

    def sizeHint(self) -> QSize:
        return QSize(UIScale.px(140 if self._compact else 180), UIScale.px(26 if self._compact else 34))

    def paintEvent(self, event) -> None:
        del event
        painter = QPainter(self)
        painter.setRenderHint(QPainter.RenderHint.Antialiasing, True)
        paw = _pawprint_pixmap(UIScale.px(self._size), rotated=True)
        if paw.isNull():
            return
        points = [
            (0.10, 0.62, 0.92),
            (0.30, 0.26, 0.80),
            (0.56, 0.68, 1.00),
            (0.82, 0.32, 0.88),
        ] if not self._compact else [
            (0.14, 0.58, 0.86),
            (0.40, 0.28, 0.76),
            (0.70, 0.58, 0.94),
        ]
        for x_frac, y_frac, scale in points:
            draw_size = max(UIScale.px(10), int(paw.width() * scale))
            scaled = paw.scaled(draw_size, draw_size, Qt.AspectRatioMode.KeepAspectRatio, Qt.TransformationMode.SmoothTransformation)
            x = int(self.width() * x_frac - scaled.width() / 2)
            y = int(self.height() * y_frac - scaled.height() / 2)
            painter.drawPixmap(x, y, scaled)


class FooterPawTrail(QWidget):
    """
    Subtle animated paw-print overlay that trails toward the Help button in the
    footer.  Active only while the player has the cat treat but hasn't yet
    discovered the cat easter-egg secret in the Help screen.

    Four prints (left, right, left, right) fade in one-by-one then fade out
    together.  The sequence repeats every 60-80 seconds.
    """

    _N            = 4      # prints per sequence
    _PAW_PX       = 26     # logical size
    _STEP_MS      = 340    # delay between successive prints appearing
    _FADE_IN_MS   = 280    # fade-in time per print
    _HOLD_MS      = 1_700  # how long all prints stay visible
    _FADE_OUT_MS  = 950    # all-out fade
    _MAX_ALPHA    = 0.72   # clearly visible for debugging

    def __init__(self, footer: "AppFooter") -> None:
        root_widget = footer._app.centralWidget() or footer
        super().__init__(root_widget)
        self._footer      = footer
        self._root        = root_widget
        self._running     = False
        self._hint_active = False

        self.setAttribute(Qt.WidgetAttribute.WA_TransparentForMouseEvents)
        self.setAttribute(Qt.WidgetAttribute.WA_ShowWithoutActivating)
        self.setGeometry(root_widget.rect())
        self.raise_()

        paw_px  = UIScale.px(self._PAW_PX)
        paw_img = _pawprint_pixmap(paw_px, angle=180)   # facing downward
        fallback_sz = QSize(paw_px, paw_px)

        self._effects: List[QGraphicsOpacityEffect] = []
        self._paw_labels: List[QLabel] = []
        for _ in range(self._N):
            lbl = QLabel(self)
            lbl.setPixmap(paw_img)
            lbl.resize(paw_img.size() if not paw_img.isNull() else fallback_sz)
            lbl.setStyleSheet("background:transparent;")
            eff = QGraphicsOpacityEffect(lbl)
            eff.setOpacity(0.0)
            lbl.setGraphicsEffect(eff)
            lbl.hide()
            self._effects.append(eff)
            self._paw_labels.append(lbl)

        self._trigger = QTimer(self)
        self._trigger.setSingleShot(True)
        self._trigger.timeout.connect(self._play)
        self._first_run = True
        self.hide()

    # ── Public control ────────────────────────────────────────────────────────

    def set_active(self, active: bool) -> None:
        """Enable or disable the hint trail."""
        if active == self._hint_active:
            return
        self._hint_active = active
        if active:
            self._first_run = True
            self.show()
            self._schedule(first=True)
        else:
            self._trigger.stop()
            self._cancel_animations()
            self.hide()

    # ── Internal ──────────────────────────────────────────────────────────────

    def _schedule(self, first: bool = False) -> None:
        delay = 15_000  # 15 s between sequences
        self._trigger.start(delay)

    def _play(self) -> None:
        if self._running or not self._hint_active:
            return
        try:
            help_btn = self._footer._help_btn
            # Map the help button's centre to our (central-widget) coordinate space.
            btn_global = help_btn.mapToGlobal(
                QPoint(help_btn.width() // 2, help_btn.height() // 2))
            btn_pos = self._root.mapFromGlobal(btn_global)
        except AttributeError:
            self._schedule()
            return

        self._running = True
        paw_w = self._paw_labels[0].width()
        paw_h = self._paw_labels[0].height()
        # Trail steps diagonally down-right toward the Help button.
        # Each successive print is dx pixels to the right and dy pixels lower.
        dx = UIScale.px(30)   # horizontal gap between prints
        dy = UIScale.px(44)   # vertical drop per step (emphasises "stepping down")

        for i, (lbl, eff) in enumerate(zip(self._paw_labels, self._effects)):
            steps_back = self._N - 1 - i          # 3 → 2 → 1 → 0
            x_alt = UIScale.px(5) if i % 2 == 0 else -UIScale.px(5)  # L/R swing
            x = btn_pos.x() - dx * steps_back - paw_w // 2 + x_alt
            y = btn_pos.y() - dy * steps_back - paw_h // 2
            lbl.move(x, y)
            eff.setOpacity(0.0)
            lbl.show()

        self._reveal_step(0)

    def _reveal_step(self, idx: int) -> None:
        if not self._hint_active:
            self._cancel_animations()
            return
        if idx >= self._N:
            QTimer.singleShot(self._HOLD_MS, self._fade_out_all)
            return
        eff  = self._effects[idx]
        anim = QPropertyAnimation(eff, b"opacity", self)
        anim.setDuration(self._FADE_IN_MS)
        anim.setStartValue(0.0)
        anim.setEndValue(self._MAX_ALPHA)
        anim.setEasingCurve(Easing.SMOOTH)
        anim.start(QAbstractAnimation.DeletionPolicy.DeleteWhenStopped)
        QTimer.singleShot(self._STEP_MS, lambda: self._reveal_step(idx + 1))

    def _fade_out_all(self) -> None:
        if not self._hint_active:
            self._cancel_animations()
            return
        for eff in self._effects:
            anim = QPropertyAnimation(eff, b"opacity", self)
            anim.setDuration(self._FADE_OUT_MS)
            anim.setStartValue(float(eff.opacity()))
            anim.setEndValue(0.0)
            anim.setEasingCurve(Easing.SMOOTH)
            anim.start(QAbstractAnimation.DeletionPolicy.DeleteWhenStopped)
        QTimer.singleShot(self._FADE_OUT_MS + 120, self._after_fadeout)

    def _after_fadeout(self) -> None:
        for lbl in self._paw_labels:
            lbl.hide()
        self._running = False
        if self._hint_active:
            self._schedule(first=False)

    def _cancel_animations(self) -> None:
        for eff in self._effects:
            eff.setOpacity(0.0)
        for lbl in self._paw_labels:
            lbl.hide()
        self._running = False

    def resizeEvent(self, event) -> None:
        super().resizeEvent(event)
        self.setGeometry(self._root.rect())


