    def _on_select(self, row: Dict[str, Any]) -> None:
        idx = row.get("applicant_index") if row else None
        if not isinstance(idx, int) or not (0 <= idx < len(self._applicants)):
            return
        applicant = self._applicants[idx]
        self._selected = applicant
